def __getattr__(name: str) -> Any:
    return getattr(parent, name)

def _profile_uses_c0f6(profile: str) -> bool:
    return profile in {PROFILE_C0F6_ONLY, PROFILE_ALL}

def _profile_uses_68da(profile: str) -> bool:
    return profile in {PROFILE_68DA_ONLY, PROFILE_ALL}

def _profile_guard_order(profile: str) -> list[str]:
    if profile not in _VALID_PROFILES:
        raise ValueError(''.join(['unknown c2e0+c0f6+68da dispatcher profile: ', format(profile, '')]))
    if profile == PROFILE_BASE_C2E0:
        return parent._profile_guard_order(parent.PROFILE_ALL)
    guards: list[str] = []
    if _profile_uses_c0f6(profile):
        guards.append(str(_C0F6_ENTRY['shape_key']))
    if _profile_uses_68da(profile):
        guards.append(str(_68DA_ENTRY['shape_key']))
    guards.extend(parent._profile_guard_order(parent.PROFILE_ALL))
    return guards

def _parent_info(inputs: dict[str, Any], profile: str) -> dict[str, Any]:
    info = dict(parent.route_info(inputs))
    route = str(info.get('route') or info.get('selected_route') or parent.selected_route(inputs))
    info['profile'] = profile
    info['route'] = route
    info['selected_route'] = route
    info['guard_order'] = _profile_guard_order(profile)
    info.setdefault('production_policy', 'weave_only')
    info.setdefault('external_fallback', None)
    info.setdefault('coverage_only', False)
    info.setdefault('missing_weave_route', False)
    return info

def _seed_info(inputs: dict[str, Any], profile: str, entry: dict[str, Any]) -> dict[str, Any]:
    parent_info = dict(parent.route_info(inputs))
    parent_route = str(parent_info.get('route') or parent_info.get('selected_route') or parent.selected_route(inputs))
    info = {'profile': profile, 'route': entry['route'], 'selected_route': entry['route'], 'selected_entrypoint': entry['entrypoint'], 'parent_route': parent_route, 'replaced_route': parent_route, 'route_kind': 'specialized', 'route_source': 'shape-specific-seed', 'coverage_class': entry['coverage_class'], 'classification': 'seed-consumed', 'coverage_only': False, 'production_policy': 'weave_only', 'external_fallback': None, 'guard_order': _profile_guard_order(profile), 'guard_id': entry['shape_key'], 'forced_fallback': False, 'selected_guard': entry['guard'], 'fallback': parent_route, 'missing_weave_route': False, 'source_task': entry['source_task'], 'source_round_doc': entry['source_round_doc'], 'selected_seed': entry['selected_seed'], 'selected_seed_task': entry['source_task'], 'replaced_seed': parent_info.get('selected_seed')}
    if entry.get('certification_policy'):
        info['certification_policy'] = entry['certification_policy']
    if entry.get('source_certification_stats'):
        info['source_certification_stats'] = entry['source_certification_stats']
        runtime_stats = kcapacity_highq.stats()
        if int(runtime_stats.get('attempts') or 0) > 0:
            info['runtime_certification_stats'] = runtime_stats
            info['runtime_fallback_count'] = runtime_stats.get('fallback_count')
    return info

def _use_c0f6(inputs: dict[str, Any], profile: str) -> bool:
    return _profile_uses_c0f6(profile) and d768d1024._use_high_dynamic_d_tcgen05(inputs)

def _use_68da(inputs: dict[str, Any], profile: str) -> bool:
    return _profile_uses_68da(profile) and (not bool(inputs.get('self_search', False))) and (not bool(inputs.get('force_fallback', False))) and kcapacity_highq._use_q4096_m49152_k64(inputs)

def selected_route_for_profile(inputs: dict[str, Any], profile: str) -> str:
    if profile not in _VALID_PROFILES:
        raise ValueError(''.join(['unknown c2e0+c0f6+68da dispatcher profile: ', format(profile, '')]))
    if profile == PROFILE_BASE_C2E0:
        return parent.selected_route(inputs)
    if _use_c0f6(inputs, profile):
        return ROUTE_C0F6_D768D1024
    if _use_68da(inputs, profile):
        return ROUTE_68DA_K64_HIGHQ
    return parent.selected_route(inputs)

def selected_route(inputs: dict[str, Any]) -> str:
    return selected_route_for_profile(inputs, PROFILE_ALL)

def selected_route_name(inputs: dict[str, Any]) -> str:
    return selected_route(inputs)

def route_info_for_profile(inputs: dict[str, Any], profile: str) -> dict[str, Any]:
    if profile not in _VALID_PROFILES:
        raise ValueError(''.join(['unknown c2e0+c0f6+68da dispatcher profile: ', format(profile, '')]))
    if profile == PROFILE_BASE_C2E0:
        return _parent_info(inputs, profile)
    if _use_c0f6(inputs, profile):
        return _seed_info(inputs, profile, _C0F6_ENTRY)
    if _use_68da(inputs, profile):
        return _seed_info(inputs, profile, _68DA_ENTRY)
    return _parent_info(inputs, profile)

def route_info(inputs: dict[str, Any]) -> dict[str, Any]:
    return route_info_for_profile(inputs, PROFILE_ALL)

def route_trace_entry(label: str, inputs: dict[str, Any], profile: str=PROFILE_ALL) -> dict[str, Any]:
    return {'label': label, 'shape_key': label, 'B': int(inputs['B']), 'Q': int(inputs['Q']), 'M': int(inputs['M']), 'D': int(inputs['D']), 'K': int(inputs['K']), 'self_search': bool(inputs.get('self_search', False)), **route_info_for_profile(inputs, profile)}

def launch_for_profile(inputs: dict[str, Any], profile: str) -> dict[str, Any]:
    if profile not in _VALID_PROFILES:
        raise ValueError(''.join(['unknown c2e0+c0f6+68da dispatcher profile: ', format(profile, '')]))
    if profile == PROFILE_BASE_C2E0:
        return parent.launch_for_eval(inputs)
    if _use_c0f6(inputs, profile):
        return d768d1024.launch_for_eval(inputs)
    if _use_68da(inputs, profile):
        return kcapacity_highq.launch_for_eval(inputs)
    return parent.launch_for_eval(inputs)

def launch_base_c2e0_for_eval(inputs: dict[str, Any]) -> dict[str, Any]:
    return launch_for_profile(inputs, PROFILE_BASE_C2E0)

def launch_c0f6_only_for_eval(inputs: dict[str, Any]) -> dict[str, Any]:
    return launch_for_profile(inputs, PROFILE_C0F6_ONLY)

def launch_68da_only_for_eval(inputs: dict[str, Any]) -> dict[str, Any]:
    return launch_for_profile(inputs, PROFILE_68DA_ONLY)

def launch_current_portfolio_for_eval(inputs: dict[str, Any]) -> dict[str, Any]:
    return launch_for_profile(inputs, PROFILE_ALL)

def launch_for_eval(inputs: dict[str, Any]) -> dict[str, Any]:
    return launch_current_portfolio_for_eval(inputs)

def _select_contract_shapes(shape_labels: str | tuple[str, ...] | list[str] | None):
    if shape_labels is None:
        return EXT_SYNTHESIS_SHAPES
    return select_named_shapes(shape_labels)

def knn_search_compile_and_launch_dispatch0618_c492_9286_c0f6_68da(*, benchmark: bool=True, shape_labels: str | tuple[str, ...] | list[str] | None=EXT_SYNTHESIS_LABELS) -> dict[str, Any]:
    from .._dispatch_runtime import evaluate
    result = evaluate(launch_for_eval, shapes=_select_contract_shapes(shape_labels), benchmark=benchmark)
    result['passed'] = bool(result.get('summary', {}).get('all_correct'))
    print(result)
    return result

def knn_search_compile_and_launch_mma_split(*, benchmark: bool=True, shape_labels: str | tuple[str, ...] | list[str] | None=EXT_SYNTHESIS_LABELS) -> dict[str, Any]:
    return knn_search_compile_and_launch_dispatch0618_c492_9286_c0f6_68da(benchmark=benchmark, shape_labels=shape_labels)
